Here's a modern MSTest test class using both `[DataRow]` and `[DynamicData]` with ValueTuples for your `PriceCalculator`:

```csharp
using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    // --- CalculateTotal: DataRow for simple inline cases ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.00, 4, 0.20, 120.00, DisplayName = "Multiple items, 20% tax")]
    [DataRow(0.00, 5, 0.15, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.10, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- CalculateTotal: invalid inputs throw ---

    [TestMethod]
    public void CalculateTotal_NegativeQuantity_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, -1, 0.1m));
        Assert.AreEqual("quantity", ex.ParamName);
    }

    [TestMethod]
    public void CalculateTotal_NegativeUnitPrice_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(-5m, 1, 0.1m));
        Assert.AreEqual("unitPrice", ex.ParamName);
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Tax below 0")]
    [DataRow(1.01, DisplayName = "Tax above 1")]
    public void CalculateTotal_InvalidTaxRate_Throws(double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));
    }

    // --- ApplyDiscount: DynamicData with ValueTuples (preferred for complex data) ---

    [TestMethod]
    [DynamicData(nameof(DiscountTestData))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> DiscountTestData =>
    [
        (100m, 10m, 90m),
        (200m, 25m, 150m),
        (50m, 0m, 50m),
        (80m, 100m, 0m),
        (0m, 50m, 0m),
        (99.99m, 50m, 49.995m),
    ];

    // --- ApplyDiscount: invalid discount throws ---

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Negative discount")]
    [DataRow(101.0, DisplayName = "Discount over 100%")]
    public void ApplyDiscount_InvalidPercent_Throws(double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));
    }
}
```

**Key patterns demonstrated:**

- **`[DataRow]`** — great for simple inline primitive values (note: `decimal` isn't a compile-time constant, so we use `double` and cast)
- **`[DynamicData]` with ValueTuples** — preferred for complex/decimal data; type-safe and readable (MSTest 3.7+)
- **`sealed` test class** — modern best practice for performance
- **Constructor init** — enables `readonly` fields
- **`Assert.ThrowsExactly<T>`** — replaces `[ExpectedException]`, allows verifying exception properties
- **`DisplayName`** — makes test explorer output readable
